#include <iostream>
#include <string>
#include <sstream>

// Assume Wallet and Cashier classes are defined above

std::string run_test() {
    std::stringstream ss;
    Wallet myWallet(100.0);
    Cashier myCashier;

    ss << "Initial wallet balance: " << myWallet.getBalance() << std::endl;

    myCashier.processPayment(myWallet, 30.0);
    ss << "Balance after payment: " << myWallet.getBalance() << std::endl;

    myCashier.addFunds(myWallet, 50.0);
    ss << "Balance after adding funds: " << myWallet.getBalance() << std::endl;

    // Additional test case: another payment
    myCashier.processPayment(myWallet, 15.0);
    ss << "Balance after second payment: " << myWallet.getBalance() << std::endl;

    return ss.str();
}

int main() {
    std::cout << run_test();
    return 0;
}
